CREATE TABLE `rb_land` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name_en` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '名称1(英文)',
  `name_zh` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '名称1(中文)',
  `image` text COLLATE utf8mb4_unicode_ci COMMENT '图片路径(英文)',
  `land_location_en` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '土地位置(英文)',
  `land_location_zh` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '土地位置(中文)',
  `land_number` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '土地编号',
  `province_id` int(10) DEFAULT '0' COMMENT '省ID',
  `city_id` int(10) DEFAULT '0' COMMENT '市ID',
  `area_id` int(10) DEFAULT '0' COMMENT '区id',
  `government_registration_number` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '政府土地注册局备案编号',
  `land_area` decimal(15,2) DEFAULT NULL COMMENT '土地面积(平方米)',
  `land_start_year` varchar(80) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '土地开始年限',
  `land_end_year` varchar(80) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '土地结束年限',
  `land_use_period` int(11) DEFAULT NULL COMMENT '使用权年限(年)',
  `remaining_use_period` int(11) DEFAULT NULL COMMENT '剩余使用年限(年)',
  `annual_government_fee` decimal(15,2) DEFAULT NULL COMMENT '每年需向政府缴纳租金费用(先令)',
  `renewal_fee_estimate` decimal(15,2) DEFAULT NULL COMMENT '到期后续期的费用预估(先令)',
  `land_price` varchar(80) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '0' COMMENT '价格',
  `owner_type` tinyint(4) DEFAULT NULL COMMENT '土地所有人类型:1-公司 2-个人',
  `owner_name_en` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '所有人名称(英文):公司名称/姓名',
  `owner_name_zh` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '所有人名称(中文):公司名称/姓名',
  `details_en` text COLLATE utf8mb4_unicode_ci COMMENT '详情(英文)',
  `details_zh` text COLLATE utf8mb4_unicode_ci COMMENT '详情(中文)',
  `latitude` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT '0' COMMENT '纬度',
  `longitude` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT '0' COMMENT '经度',
  `create_time` int(10) DEFAULT '0',
  `update_time` int(10) DEFAULT '0',
  `admin_id` int(10) DEFAULT '0' COMMENT '经纪人',
  `is_recommend` tinyint(1) DEFAULT '0' COMMENT '1是0否推荐',
  `land_nature` tinyint(2) NOT NULL DEFAULT '0' COMMENT '1工业用地2.商业用地3.住宅用地',
  `reply_status` tinyint(2) NOT NULL DEFAULT '1' COMMENT '0待审核1通过2拒绝',
  `reply_reason` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '拒绝原因',
  PRIMARY KEY (`id`),
  KEY `idx_land_number` (`land_number`),
  KEY `idx_government_registration_number` (`government_registration_number`)
) ENGINE=InnoDB AUTO_INCREMENT=112 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='土地信息表';
