--
-- Table structure for table `rb_estate`
--

DROP TABLE IF EXISTS `rb_estate`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `rb_estate` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '楼盘ID',
  `estate_name_zh` varchar(150) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '楼盘名称(中文)',
  `estate_name_en` varchar(150) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '楼盘名称(英文)',
  `alias_name_zh` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '楼盘别名(中文)',
  `alias_name_en` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '楼盘别名(英文)',
  `listing_type` tinyint(1) DEFAULT '1' COMMENT '1..二手房2.小区4.新房',
  `banner_images` text COLLATE utf8mb4_unicode_ci COMMENT '轮播图',
  `vr_url` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'VR地址URL',
  `vr_img` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `video_url` text COLLATE utf8mb4_unicode_ci COMMENT '视频',
  `longitude` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '经度',
  `latitude` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '纬度',
  `province_id` int(10) DEFAULT '0' COMMENT '省id',
  `city_id` int(10) DEFAULT '0' COMMENT '市id',
  `area_id` int(10) DEFAULT '0' COMMENT '区域id',
  `address_zh` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '详细地址(中文)',
  `address_en` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '详细地址(英文)',
  `estate_type` varchar(80) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '1.Apartment \r\n2.Villa\r\n3.Bungalow \r\n4.Mansionette \r\n5.Office Space\r\n6.Commercial Space\r\n7.Duplex\r\n8.Penthouse \r\n9.Ambassadorial Villa',
  `opening_time` int(11) DEFAULT NULL COMMENT '开盘时间(时间戳)',
  `unit_price` decimal(10,2) DEFAULT NULL COMMENT '单价(元/平方米)',
  `min_total_price` decimal(12,2) DEFAULT NULL COMMENT '最少总价(元)',
  `max_total_price` decimal(12,2) DEFAULT NULL COMMENT '最高总价(元)',
  `code` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '楼盘编号',
  `sort` int(11) DEFAULT '0' COMMENT '排序(数字越大越靠前)',
  `status` tinyint(1) DEFAULT '1' COMMENT '状态(1显示,0隐藏)',
  `sale_status` tinyint(1) DEFAULT '1' COMMENT '销售状态1在售2预售',
  `is_recommend` tinyint(1) DEFAULT '0' COMMENT '1是0否推荐',
  `admin_id` int(10) DEFAULT '0' COMMENT '顾问id',
  `is_hot` tinyint(1) DEFAULT '0' COMMENT '1是0否热门楼盘',
  `max_area` decimal(10,2) DEFAULT '0.00' COMMENT '面积/平方米',
  `min_area` decimal(10,2) DEFAULT '0.00' COMMENT '面积',
  `content_zh` text COLLATE utf8mb4_unicode_ci COMMENT '详情',
  `content_en` text COLLATE utf8mb4_unicode_ci,
  `reply_status` tinyint(2) NOT NULL DEFAULT '1' COMMENT '0待审核1通过2拒绝',
