INSERT INTO `rb_estate` VALUES (43,'TSAVORITE GARDEN','TSAVORITE GARDEN','TSAVORITE GARDEN','TSAVORITE GARDEN',4,'https://www.afbeke.com/storage/default/20250919/ff9b2f9e9648ebdaed90a74c655d551ddf88dc67.jpeg,https://www.afbeke.com/storage/default/20250919/e841e905f874f5b9dd8977bee4be30c898ca8312.jpeg,https://www.afbeke.com/storage/default/20250919/8bb9fad492f933ac761d7d6cbfa6d6b6471e7a46.jpeg,blob:https://www.afbeke.com/aef3819c-7541-4c49-a9b7-c4626df10d56,https://www.afbeke.com/storage/default/20250919/564a2c35aab296d64b8f5028b7a3cb0e2829e3c3.jpg','','','','115.9133040','28.6770060',52995,145494,145535,'Wood Avenue','Wood Avenue','1',1751353200,108333.00,65000000.00,12500000.00,'3',0,1,1,0,25,0,130.00,60.00,'<p style=\"text-align: left;\"><br></p>','<p><span style=\"font-size: 16px; font-family: 微软雅黑;\"><u><strong>TSAVORITE GARDEN</strong></u></span></p><p><span style=\"color: rgb(34, 34, 34); background-color: rgb(255, 255, 255); font-size: 14px; font-family: 微软雅黑;\">Tsavorite Gardens is located on Wood Garden Road, off Wood Avenue, Kilimani. It offers 1–3 bedroom apartments in a 17‑storey tower with gym, rooftop terrace &amp; backup. As a leading real estate investment company in Nairobi, Kenya, we are dedicated to providing Affordable Amazing Apartments that pave the way for your journey towards financial empowerment.</span></p><p><span style=\"color: rgb(54, 88, 226); font-size: 14px; font-family: 微软雅黑;\"><strong>Amenities:</strong></span></p><p style=\"text-align: left;\"><span style=\"font-size: 14px; font-family: 微软雅黑;\">⚡️Full backup generator</span></p><p style=\"text-align: left;\"><span style=\"font-size: 14px; font-family: 微软雅黑;\">?Borehole</span></p><p style=\"text-align: left;\"><span style=\"font-size: 14px; font-family: 微软雅黑;\">?Central Garden</span></p><p style=\"text-align: left;\"><span style=\"font-size: 14px; font-family: 微软雅黑;\">? Out door kids play yard</span></p><p style=\"text-align: left;\"><span style=\"font-size: 14px; font-family: 微软雅黑;\">⛱️Sky lounge</span></p><p style=\"text-align: left;\"><span style=\"font-size: 14px; font-family: 微软雅黑;\">?Common kitchen &amp; Club</span></p><p style=\"text-align: left;\"><span style=\"font-size: 14px; font-family: 微软雅黑;\">?️CCTV+Access control</span></p><p style=\"text-align: left;\"><span style=\"font-size: 14px; font-family: 微软雅黑;\">??‍♀️Equipped 300sqm gym</span></p><p style=\"text-align: left;\"><span style=\"font-size: 14px; font-family: 微软雅黑;\">?️3basements+Gf+mezzanine </span></p><p style=\"text-align: left;\"><span style=\"font-size: 14px; font-family: 微软雅黑;\">?️Supermarket, dry cleaning, pharmacy, salon, café </span></p><p style=\"text-align: left;\"><br></p><p style=\"text-align: left;\"><span style=\"font-size: 14px; font-family: 微软雅黑;\">?</span><span style=\"color: rgb(54, 88, 226); font-size: 14px; font-family: 微软雅黑;\"><strong>Features:</strong></span></p><ul><li style=\"text-align: left;\"><span style=\"font-size: 14px; font-family: 微软雅黑;\">Smart lock</span></li><li style=\"text-align: left;\"><span style=\"font-size: 14px; font-family: 微软雅黑;\">Spotlights</span></li><li style=\"text-align: left;\"><span style=\"font-size: 14px; font-family: 微软雅黑;\">Fitted cooker</span></li><li style=\"text-align: left;\"><span style=\"font-size: 14px; font-family: 微软雅黑;\">Fitted exhaust hood</span></li><li style=\"text-align: left;\"><span style=\"font-size: 14px; font-family: 微软雅黑;\">Full length balconies</span></li><li><span style=\"font-size: 14px; font-family: 微软雅黑;\">Smart mirror with touch switch for lighting and anti-fogging.</span></li><li style=\"text-align: left;\"><span style=\"font-size: 14px; font-family: 微软雅黑;\">Luxurious new landmark nestled in heart of Kilimani enjoying convenience with tranquility.</span></li></ul><p style=\"text-align: left;\"><span style=\"font-size: 14px; font-family: 微软雅黑;\"><strong>Unit sizes and prices:</strong></span></p><div data-w-e-type=\"todo\" style=\"text-align: left;\"><input type=\"checkbox\" disabled=\"\" checked