--
-- Table structure for table `rb_estate_listing`
--

DROP TABLE IF EXISTS `rb_estate_listing`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `rb_estate_listing` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `estate_id` int(11) DEFAULT NULL COMMENT '楼盘ID',
  `house_img` text COMMENT '图片',
  `house_number` varchar(255) DEFAULT NULL COMMENT '房源编号',
  `house_name_zh` varchar(255) DEFAULT NULL COMMENT '房源名称(中文)',
  `house_name_en` varchar(255) DEFAULT NULL COMMENT '房源名称(英文)',
  `estate_listing_type` tinyint(2) DEFAULT NULL COMMENT '1.Villa 别墅\r\n2.Apartment 公寓\r\n3.Penthouse  高层公寓\r\n4.Duplex  复式公寓\r\n5.Triplex  三层公寓\r\n6.Bungalow  洋房\r\n7.Stand-alone 独立式住宅\r\n8.Sky Villas 空中别墅',
  `description_zh` text COMMENT '房源介绍(中文)',
  `description_en` text COMMENT '房源介绍(英文)',
  `listing_type` tinyint(1) DEFAULT NULL COMMENT '房源类型1.二手房2.小区3.租房',
  `sale_type` tinyint(1) DEFAULT NULL COMMENT '出售类型1.出售2.出租',
  `sale_type_other` tinyint(1) DEFAULT '1' COMMENT '1整租2合租',
  `surrounding_facilities_zh` text COMMENT '周边配套(中文)',
  `surrounding_facilities_en` text COMMENT '周边配套(英文)',
  `transportation_zh` text COMMENT '交通出行(中文)',
  `transportation_en` text COMMENT '交通出行(英文)',
  `highlights_zh` text COMMENT '核心实点(中文)',
  `highlights_en` text COMMENT '核心实点(英文)',
  `inner_area` decimal(10,2) DEFAULT '0.00' COMMENT '套内面积(㎡)',
  `construction_area` decimal(10,2) DEFAULT '0.00' COMMENT '建筑面积(㎡)',
  `price` decimal(12,2) DEFAULT '0.00' COMMENT '价格',
  `total_price` decimal(12,2) DEFAULT '0.00' COMMENT '总价格',
  `x_common_type_id` int(11) DEFAULT '0' COMMENT '房屋朝向ID',
  `common_type_id` int(11) DEFAULT NULL COMMENT '户型ID',
  `l_common_type_id` int(11) DEFAULT '0' COMMENT '楼层类型id',
  `floor_height` varchar(80) DEFAULT NULL COMMENT '楼层高度',
  `current_floor` varchar(80) DEFAULT NULL COMMENT '所在楼层',
  `building_age` varchar(80) DEFAULT NULL COMMENT '楼龄',
  `zx_type` tinyint(1) DEFAULT NULL COMMENT '装修情况(1.精装 2.普通装修 3.毛坯房)',
  `building_structure_zh` varchar(100) DEFAULT NULL COMMENT '建筑结构(中文)',
  `building_structure_en` varchar(100) DEFAULT NULL COMMENT '建筑结构(英文)',
  `elevator_ratio` varchar(100) DEFAULT NULL COMMENT '梯户比例',
  `listing_time` int(11) DEFAULT '0' COMMENT '挂牌时间',
  `transaction_ownership` varchar(100) DEFAULT NULL COMMENT '交易权属',
  `house_purpose` tinyint(1) DEFAULT '1' COMMENT '房屋用途(1.普通住宅 2商业类3.别墅4.四合院5车位6.其它)',
  `house_ownership` tinyint(1) DEFAULT '1' COMMENT '房屋所属(1.共有 2.非共有)',
  `verification_code` varchar(100) DEFAULT NULL COMMENT '房源验证编码',
  `mortgage_info` tinyint(1) DEFAULT '2' COMMENT '抵押信息(1.抵押 2.无抵押)',
  `create_time` int(11) DEFAULT '0' COMMENT '创建时间(时间戳)',
  `f_content_zh` text COMMENT '详情',
  `f_content_en` text,
  `admin_id` int(10) DEFAULT '0' COMMENT '经纪人id',
  `is_recommend` tinyint(1) DEFAULT '0' COMMENT '1是0否推荐',
  `vr_url` text COMMENT 'vr',
  `vr_img` varchar(255) DEFAULT NULL COMMENT 'vr封面图',
  `video_url` text COMMENT '视频url',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '1展示0隐藏',
  `reply_status` tinyint(2) NOT NULL DEFAULT '1' COMMENT '0待审核1通过2拒绝',
  `reply_reason` varchar(100) DEFAULT NULL COMMENT '拒绝原因',
  PRIMARY KEY (`id`),
  KEY `idx_common_type_id` (`common_type_id`),
  KEY `idx_x_common_type_id` (`x_common_type_id`),
  KEY `idx_create_time` (`create_time`)
) ENGINE=InnoDB AUTO_INCREMENT=144 DEFAULT CHARSET=utf8mb4 COMMENT='房源信息表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `rb_estate_listing`
--

LOCK TABLES `rb_estate_listing` WRITE;
/*!40000 ALTER TABLE `rb_estate_listing` DISABLE KEYS */;
INSERT INTO `rb_estate_listing` VALUES (105,135,'https://www.afbeke.com//storage/default/20250704/e7e3d344dd002f2435bef0c4a2456a9942136b4d.jpg,https://www.afbeke.com//storage/default/20250704/33aceff93ca907db2d3bafc972035572335d919d.jpg,https://www.afbeke.com//storage/default/20250704/fbbc20fd5809406edd0219bc7c80ecc0d5e349f8.jpg,https://www.afbeke.com//storage/default/20250704/3cc5b017501736c3581ed37e9dc92dd6630e6747.jpg,https://www.afbeke.com//storage/default/20250704/baa7871faff24f65b8169a7b677e9ee855f56d27.jpg','001','','PINECREST RESIDENCE',2,'<p><br></p>','<p><br></p>',3,2,1,'','YAYA CENTRE, CHANDARANA MALL,CJ RESTURANT','','road','','5mins to ngong rd',53.00,53.00,70000.00,70000.00,11,55,20,'3 m','10','3',1,'','skyscraper with terraces','3 elevator per floor',1751612400,'management',1,1,'0',2,1751626182,'<p><br></p>','<p style=\"text-align: left;\"><span style=\"font-size: 16px; font-family: 微软雅黑;\"><u><strong>PINCREST RESIDENCE UNITS FOR RENT</strong></u></span></p><p style=\"text-align: left;\"><span style=\"font-family: 微软雅黑;\">Situated in a serene and secure environment, this unit offers:</span></p><div data-w-e-type=\"todo\" style=\"text-align: left;\"><input type=\"checkbox\" disabled=\"\"><span style=\"font-family: 微软雅黑;\">Space &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; </span></div><div data-w-e-type=\"todo\" style=\"text-align: left;\"><input type=\"checkbox\" disabled=\"\"><span style=\"font-family: 微软雅黑;\">Security</span></div><div data-w-e-type=\"todo\" style=\"text-align: left;\"><input type=\"checkbox\" disabled=\"\"><span style=\"font-family: 微软雅黑;\">Privacy </span></div><div data-w-e-type=\"todo\" style=\"text-align: left;\"><input type=\"checkbox\" disabled=\"\"><span style=\"font-family: 微软雅黑;\">Excellent road access</span></div><p style=\"text-align: left;\"><span style=\"font-family: 微软雅黑;\">Location- Kilimani along Kindaruma road</span></p><p style=\"text-align: left;\"><span style=\"color: rgb(54, 88, 226); font-size: 16px; font-family: 微软雅黑;\"><u><strong>Features and amenities</strong></u></span></p><p style=\"text-align: left;\"><span style=\"font-family: 微软雅黑;\">● Heated swimming pool</span></p><p style=\"text-align: left;\"><span style=\"font-family: 微软雅黑;\">● Steam sauna</span></p><p style=\"text-align: left;\"><span style=\"font-family: 微软雅黑;\">● Fully fitted gym</span></p><p style=\"text-align: left;\"><span style=\"font-family: 微软雅黑;\">● Fully fitted kitchen </span></p><p style=\"text-align: left;\"><span style=\"font-family: 微软雅黑;\">● Full backup generator </span></p><p style=\"text-align: left;\"><span style=\"font-family: 微软雅黑;\">● Ample parking </span></p><p style=\"text-align: left;\"><span style=\"font-family: 微软雅黑;\">● High speed lifts </span></p><p style=\"text-align: left;\"><span style=\"font-family: 微软雅黑;\">● Smart lock door</span></p><p style=\"text-align: left;\"><span style=\"font-family: 微软雅黑;\">● Borehole </span></p><p style=\"text-align: left;\"><span style=\"font-family: 微软雅黑;\">Pincrest residence is in close proximity to these important facilities;</span></p><div data-w-e-type=\"todo\" style=\"text-align: left;\"><input type=\"checkbox\" disabled=\"\"><span style=\"font-family: 微软雅黑;\">Top schools</span></div><div data-w-e-type=\"todo\" style=\"text-align: left;\"><input type=\"checkbox\" disabled=\"\"><span style=\"font-family: 微软雅黑;\">Hospitals</span></div><div data-w-e-type=\"todo\" style=\"text-align: left;\"><input type=\"checkbox\" disabled=\"\"><span style=\"font-family: 微软雅黑;\">Shopping malls and restaitants</span></div><div data-w-e-type=\"todo\" style=\"text-align: left;\"><input type=\"checkbox\" disabled=\"\"><span style=\"font-family: 微软雅黑;\">Excellent road access</span></div><p style=\"text-align: left;\"><span style=\"font-size: 16px; font-family: 微软雅黑;\"><u><strong>Unit sizes and prices</strong></u></span></p><p style=\"text-align: left;\"><span style=\"font-family: 微软雅黑;\">1 bedrooms - all sold out</span></p><p style=\"text-align: left;\"><span style=\"font-family: 微软雅黑;\">2 bedrooms - 112 sqm</span></p><p style=\"text-align: left;\"><span style=\"font-size: 16px; font-family: 微软雅黑;\"><strong>contact us today!!</strong></span></p><p style=\"text-align: left;\"><span style=\"font-family: 微软雅黑;\">Contact: 0768909663</span></p>',25,1,'NA','https://www.afbeke.com//storage/default/20250704/68ecb956f9adf8eee2768304ac9fb3723a765e26.jpg','',1,1,''),(108,0,'https://www.afbeke.com//storage/default/20250704/7c1a8ba311370634e7468b04eb58d86a3ff485fe.jpeg,https://www.afbeke.com//storage/default/20250704/32c985afddd80cf57050881f5f1a0687f9ec3085.jpeg,https://www.afbeke.com//storage/default/20250704/54669a2cc755ff86d8e8ea4b6f23450683e9c03c.jpeg,https://www.afbeke.com//storage/default/20250704/63f8891978e836023fcbd7e89e1d0c50da3e9902.jpeg,https://www.afbeke.com//storage/default/20250704/fc7df05cb6c2cf455452cc34742caee2fc3f3759.jpeg','23','THE LOFTS','THE LOFTS',2,'<h2 style=\"text-align: start;\">The Lofts At Wood Avenue - Kilimani Apartment</h2><p>Located about 10 minutes by car from Uhuru Park, <strong>The Lofts At Wood Avenue - Kilimani Apartment</strong> Nairobi gives access to a number of tourist attractions in the area.</p><p><strong>The Lofts At Wood Avenue - Kilimani Apartment</strong> comprises a balcony and a seating area featuring a sofa set, and modern comforts like a multi-channel television. Bathrooms come with a separate toilet and a shower. Additionally, you\'ll find dryers and towels.</p><p>There are a refrigerator, an oven, and kitchenware provided for guests at the apartment. This accommodation is only a stone\'s throw from the pub Jiweke Tavern.</p><p>This apartment lies at a moderate distance from Shifteye Gallery. David Sheldrick Wildlife Trust is within a 10-minute drive of the property. The nearest airport is Wilson, 10 km from this apartment, and Prestige Plaza bus station is only 350 metres away.</p><h3>Facilities</h3><h3>General</h3><p>Wi-Fi</p><p>Safe deposit box</p><h4>Dining</h4><p>Dr